using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and communication." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on civilization." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming education.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and competitive programming. Former ACM ICPC world finalist." },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", DepartmentName = "Computer Science", Code = "CS 310", Title = "Web Application Development", Description = "Modern web development with ASP.NET Core, Blazor, and cloud deployment. Covers front-end, back-end, and database integration.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez spent a decade in industry at major tech companies before joining academia. She focuses on practical, project-based learning.", IsFeatured = true },
            new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics", Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is an award-winning educator with a passion for making calculus accessible to all students." },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", DepartmentName = "Mathematics", Code = "MATH 220", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson's research focuses on computational linear algebra and its applications in machine learning.", IsFeatured = true },
            new() { Id = 6, DepartmentId = 3, DepartmentCode = "PHYS", DepartmentName = "Physics", Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres brings complex physics concepts to life through innovative demonstrations and real-world applications." },
            new() { Id = 7, DepartmentId = 3, DepartmentCode = "PHYS", DepartmentName = "Physics", Code = "PHYS 250", Title = "Modern Physics", Description = "Special relativity, quantum mechanics, atomic and nuclear physics. Prerequisites: PHYS 101, MATH 101.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is an active researcher in quantum computing and brings cutting-edge discoveries into the classroom." },
            new() { Id = 8, DepartmentId = 4, DepartmentCode = "ENG", DepartmentName = "English", Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading, thinking, and writing skills. Emphasis on argumentation and research-based essays.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published author and writing coach who has mentored hundreds of students in academic writing.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 4, DepartmentCode = "ENG", DepartmentName = "English", Code = "ENG 215", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present day.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Rachel Green", InstructorBio = "Dr. Green specializes in 20th-century American fiction and has published two books on the Harlem Renaissance." },
            new() { Id = 10, DepartmentId = 5, DepartmentCode = "HIST", DepartmentName = "History", Code = "HIST 101", Title = "World Civilizations", Description = "Survey of major world civilizations from ancient times to the modern era. Explores cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown is a historian specializing in cross-cultural exchange and global trade networks." },
            new() { Id = 11, DepartmentId = 5, DepartmentCode = "HIST", DepartmentName = "History", Code = "HIST 305", Title = "The Digital Age", Description = "History of computing, the internet, and digital culture from the 1940s to today.", Credits = 3, Schedule = "Fri 10:00 AM–12:45 PM", InstructorName = "Dr. Lisa Nguyen", InstructorBio = "Dr. Nguyen bridges history and technology, researching how digital tools reshape society and memory.", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request) => _enrollments.Add(request);
}

