@page "/courses"
@using CourseCatalog.Services
@using CourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<div class="container">
    <h1 class="my-4">Browse Courses</h1>

    <form method="get" class="row g-3 mb-4">
        <div class="col-md-6">
            <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
        </div>
        <div class="col-md-4">
            <select name="departmentId" class="form-select">
                <option value="">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </form>

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@course.DepartmentName</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using CourseCatalog.Services
@using CourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

<div class="container">
    @if (course is null)
    {
        <div class="alert alert-warning my-4">Course not found.</div>
    }
    else
    {
        <nav class="my-3">
            <a href="/courses">← Back to Courses</a>
        </nav>

        <h1>@course.Code — @course.Title</h1>

        <div class="row mt-4">
            <div class="col-md-8">
                <h4>Description</h4>
                <p>@course.Description</p>

                <h4 class="mt-4">Schedule</h4>
                <p>@course.Schedule</p>

                <h4 class="mt-4">Instructor</h4>
                <p><strong>@course.InstructorName</strong></p>
                <p>@course.InstructorBio</p>
            </div>
            <div class="col-md-4">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Course Info</h5>
                        <ul class="list-unstyled">
                            <li><strong>Code:</strong> @course.Code</li>
                            <li><strong>Credits:</strong> @course.Credits</li>
                            <li><strong>Department:</strong> @course.DepartmentName</li>
                        </ul>
                        <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100">Request Enrollment</a>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using CourseCatalog.Services
@using CourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="my-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted!</h4>
            <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received. You will be notified by email once it is processed.</p>
        </div>
        <a href="/courses" class="btn btn-primary">Browse More Courses</a>
    }
    else
    {
        <p>Fill out the form below to request enrollment in a course.</p>

        <form method="post" class="row g-3" style="max-width: 600px;">
            <AntiforgeryToken />

            <div class="col-12">
                <label for="studentName" class="form-label">Full Name</label>
                <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
            </div>

            <div class="col-12">
                <label for="studentId" class="form-label">Student ID</label>
                <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required placeholder="e.g., STU-12345" />
            </div>

            <div class="col-12">
                <label for="courseId" class="form-label">Course</label>
                <select id="courseId" name="Model.CourseId" class="form-select" required>
                    <option value="">— Select a course —</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code — @course.Title</option>
                    }
                </select>
            </div>

            <div class="col-12">
                <button type="submit" class="btn btn-success">Submit Request</button>
                <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </div>
        </form>
    }
</div>

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = "";

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;

        if (HttpMethods.IsPost(HttpContext.Request.Method) &&
            !string.IsNullOrWhiteSpace(Model.StudentName) &&
            !string.IsNullOrWhiteSpace(Model.StudentId) &&
            Model.CourseId > 0)
        {
            Catalog.SubmitEnrollment(Model);
            selectedCourseTitle = courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title ?? "Unknown";
            submitted = true;
        }
    }

    [CascadingParameter] public HttpContext HttpContext { get; set; } = default!;
}

